    voronoi = pf.nodes.shader.voronoi(vector=noise.fac.astype(dtype=mathutils.Vector), scale=10.0)
    
    color_ramp = pf.nodes.shader.color_ramp(
        fac=voronoi.color.astype(dtype=float),
        points=[(0.4, (0.0, 0.0, 0.0, 1.0)), (0.573, (1.0, 1.0, 1.0, 1.0))],
        interpolation='LINEAR',
    )
    
