    noise_1 = pf.nodes.shader.noise(vector=mapping_1, scale=102.481506, detail=15.0, roughness=0.7667)
    
    voronoi_1 = pf.nodes.shader.voronoi(vector=noise_1.fac.astype(dtype=mathutils.Vector), scale=10.044822)
    
    color_ramp_1 = pf.nodes.shader.color_ramp(
        fac=voronoi_1.color.astype(dtype=float),
        points=[(0.334, (0.0, 0.0, 0.0, 1.0)), (0.717, (1.0, 1.0, 1.0, 1.0))],
        interpolation='LINEAR',
    )
    
    mix_rgb_factor = color_ramp.color.astype(dtype=mathutils.Vector) * color_ramp_1.color.astype(dtype=mathutils.Vector)
    
    mapping_2 = pf.nodes.shader.mapping(vector=coord.uv, scale=(1.0, 1.0, 0.0))
    
    noise_2 = pf.nodes.shader.noise(vector=mapping_2, scale=7.187254)
    
    color_ramp_2 = pf.nodes.shader.color_ramp(
        fac=noise_2.fac,
        points=[(0.413, (0.381, 0.238, 0.118, 1.0)), (0.742, (0.497, 0.503, 0.468, 1.0))],
        interpolation='LINEAR',
    )
    
    mix_rgb = pf.nodes.shader.mix_rgb(
        factor=mix_rgb_factor.astype(dtype=float),
        a=mathutils.Color((0.191, 0.045, 0.01)),
        b=color_ramp_2.color,
    )
    
    principled = pf.nodes.shader.principled_bsdf(
        base_color=mix_rgb,
        roughness=0.4409,
        ior=1.45,
        subsurface_method='RANDOM_WALK_SKIN',
        subsurface_ior=1.4,
        subsurface_anisotropy=0.0,
        distribution='GGX',
        emission_color=mathutils.Color((0.0, 0.0, 0.0)),
        emission_strength=1.0,
    )
    
    glass = pf.nodes.shader.glass_bsdf(ior=1.45, normal=(0.0, 0.0, 0.0), distribution='BECKMANN')
    
    mix_shader = pf.nodes.shader.mix_shader(factor=0.2, a=principled, b=glass)
    return pf.MaterialShader(
        surface=mix_shader,
        displacement=None,
        volume=None,
    )




