def shader_snake_plant():
    # Code generated by procfunc v0.100.0_siggraph
    
    color_ramp = pf.nodes.shader.color_ramp(
        fac=0.001 * 2.0,
        points=[(0.361, (1.0, 1.0, 1.0, 1.0)), (0.381, (0.0, 0.0, 0.0, 1.0))],
        interpolation='LINEAR',
    )
    
    coord = pf.nodes.shader.coord()
    
    mapping = pf.nodes.shader.mapping(coord.object)
    
    noise = pf.nodes.shader.noise(vector=mapping, scale=0.674211, roughness=1.0)
    
    wave_vector = noise.fac.astype(dtype=mathutils.Vector) * (1.0, 1.0, 0.6)
    wave = pf.nodes.shader.wave(
        vector=wave_vector + mapping,
        scale=1.8603,
        distortion=3.006972,
        detail_scale=2.024195,
        detail_roughness=2.0,
        bands_direction='Z',
    )
    
    mix_a = wave.fac > 0.492698
    
    mapping_1 = pf.nodes.shader.mapping(vector=coord.object, scale=(7.0, 7.0, 0.05))
    
    noise_1 = pf.nodes.shader.noise(vector=mapping_1, scale=38.821468)
    
    color_ramp_1 = pf.nodes.shader.color_ramp(
        fac=mix_a * noise_1.fac,
        points=[(0.232, (0.0, 0.0, 0.0, 1.0)), (0.631, (1.0, 1.0, 1.0, 1.0))],
        interpolation='LINEAR',
    )
    color_ramp_2 = pf.nodes.shader.color_ramp(
        fac=wave.fac,
        points=[(0.776, (0.0, 0.0, 0.0, 1.0)), (0.813, (1.0, 1.0, 1.0, 1.0))],
        interpolation='LINEAR',
    )
    
    mix_rgb = pf.nodes.shader.mix_rgb(
        factor=0.844434,
        a=color_ramp_1.color,
        b=color_ramp_2.color,
        blend_type='ADD',
    )
    
    color_ramp_3 = pf.nodes.shader.color_ramp(
        fac=mix_rgb.astype(dtype=float),
        points=[(0.0, (0.081, 0.391, 0.118, 1.0)), (1.0, (0.014, 0.039, 0.014, 1.0))],
        interpolation='LINEAR',
    )
    
    mix_rgb_1 = pf.nodes.shader.mix_rgb(
        factor=color_ramp.color.astype(dtype=float),
        a=mathutils.Color((0.593, 0.785, 0.087)),
        b=color_ramp_3.color,
    )
    
    principled = pf.nodes.shader.principled_bsdf(
        base_color=mix_rgb_1,
        roughness=10.851682,
        ior=1.45,
        subsurface_method='RANDOM_WALK_SKIN',
        subsurface_ior=1.4,
        subsurface_anisotropy=0.0,
        distribution='GGX',
        coat_roughness=0.0,
        emission_color=mathutils.Color((0.0, 0.0, 0.0)),
        emission_strength=1.0,
    )
    return pf.MaterialShader(
        surface=principled,
        displacement=None,
        volume=None,
    )




